/**
 * Mock data for the Data › Orders record-explorer page.
 *
 * Ported from /Users/mac/Downloads/MAGELLAN UX/Data/magellan-data-orders.html
 * Currency converted ฿ → $ (same digits, $ symbol) per Magellan currency rule.
 *
 * An order is a neutral record — line items, value, margin, and a status
 * timeline. Margin inherits landed cost from Operations (computed/partial
 * provenance survives into the record). The verdict (is margin too thin? push
 * a source?) belongs to a Room, never here.
 *
 * The template builds 52 deterministic orders with a seeded RNG (mulberry32,
 * seed 73). We reproduce that generator verbatim so the rows are stable across
 * renders, then freeze the array (sorted newest-first) and expose the typed
 * column / filter / calendar metadata + pure helpers.
 */

/* ─────────────────────────── Types ─────────────────────────── */

export type OrderStatus = "completed" | "processing" | "cancelled" | "refunded";
export type Fulfillment = "delivered" | "shipped" | "processing" | "pending";
export type Provenance = "computed" | "partial";
export type Payment = "Credit Card" | "PromptPay" | "Bank Transfer";
export type Source = "organic" | "google_ads" | "meta_ads" | "direct" | "email" | "line_oa";

/** A single line item: [name, qty, amount, marginRatio]. */
export type LineItem = [string, number, number, number];

export interface OrderRecord {
  id: string;
  custId: string;
  /** ISO date (YYYY-MM-DD) — used for sorting & range filtering */
  date: string;
  /** ms epoch of the order moment, for stable date sort */
  ts: number;
  time: string;
  customer: string;
  email: string;
  phone: string;
  status: OrderStatus;
  items: number;
  lines: LineItem[];
  subtotal: number;
  shipping: number;
  discount: number;
  total: number;
  /** average margin %, 0 when cancelled */
  margin: number;
  prov: Provenance;
  payment: Payment;
  source: Source;
  fulfillment: Fulfillment;
  district: string;
  zip: string;
  billName: string;
  billLines: string[];
  shipName: string;
  shipLines: string[];
  slot: string;
  /** timeline steps: [label, timestamp] */
  timeline: Array<[string, string]>;
}

export type ColumnKey =
  | "order"
  | "customer"
  | "status"
  | "items"
  | "total"
  | "margin"
  | "payment"
  | "source"
  | "fulfillment"
  | "district";

export interface ColumnDef {
  k: ColumnKey;
  label: string;
  on: boolean;
  num?: boolean;
  fixed?: boolean;
}

export type FilterKey = "status" | "source" | "fulfillment" | "payment";

/* ─────────────────────────── Seeded RNG (mulberry32, seed 73) ─────────────────────────── */

function mulberry32(a: number): () => number {
  return function () {
    a |= 0;
    a = (a + 0x6d2b79f5) | 0;
    let t = Math.imul(a ^ (a >>> 15), 1 | a);
    t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}
const rng = mulberry32(73);
const pick = <T>(arr: readonly T[]): T => arr[Math.floor(rng() * arr.length)];
const between = (a: number, b: number): number => a + Math.floor(rng() * (b - a + 1));

