function fulfillmentFor(st: OrderStatus): Fulfillment {
  if (st === "completed") return pick<Fulfillment>(["delivered", "delivered", "shipped"]);
  if (st === "processing") return "processing";
  if (st === "cancelled") return "pending";
  return "pending";
}

function buildTimeline(status: OrderStatus, dt: Date): Array<[string, string]> {
  const fmt = (d: Date) =>
    d
      .toLocaleString("en-GB", { day: "numeric", month: "short", hour: "2-digit", minute: "2-digit" })
      .replace(",", "");
  const t: Array<[string, string]> = [];
  let c = new Date(dt);
  t.push(["Order placed", fmt(c)]);
  c = new Date(c.getTime() + 60000);
  t.push(["Payment captured", fmt(c)]);
  if (status === "cancelled") {
    c = new Date(c.getTime() + 5400000);
    t.push(["Cancelled by customer", fmt(c)]);
    c = new Date(c.getTime() + 300000);
    t.push(["Refund issued", fmt(c)]);
    return t;
  }
  if (status === "refunded") {
    c = new Date(c.getTime() + 86400000);
    t.push(["Delivered", fmt(c)]);
    c = new Date(c.getTime() + 172800000);
    t.push(["Refund requested", fmt(c)]);
    c = new Date(c.getTime() + 3600000);
    t.push(["Refund issued", fmt(c)]);
    return t;
  }
  c = new Date(c.getTime() + 5400000);
  t.push(["In production", fmt(c)]);
  if (status === "processing") return t;
  c = new Date(c.getTime() + 18000000);
  t.push(["Out for delivery", fmt(c)]);
  c = new Date(c.getTime() + 4800000);
  t.push(["Delivered", fmt(c)]);
  return t;
}

function genOrder(i: number): OrderRecord {
  const fn = pick(FIRST);
  const ln = pick(LAST);
  const customer = `${fn} ${ln}`;
  const nItems = between(1, 4);
  const lines: LineItem[] = [];
  let subtotal = 0;
  let mAcc = 0;
  for (let k = 0; k < nItems; k++) {
    const p = pick(PRODUCTS);
    const q = rng() < 0.85 ? 1 : 2;
    const amt = p[1] * q;
    lines.push([p[0], q, amt, p[2]]);
    subtotal += amt;
    mAcc += amt * p[2];
  }
  const status = pick(STATUSES);
  const shipping = rng() < 0.4 ? 0 : between(60, 180);
  const discount = rng() < 0.22 ? between(100, 400) : 0;
  const total = subtotal + shipping - discount;
  const marginPct = status === "cancelled" ? 0 : (mAcc / subtotal) * 100;
  const prov: Provenance = rng() < 0.18 ? "partial" : "computed";
  const d = DISTRICTS[between(0, DISTRICTS.length - 1)];
  const daysAgo = between(0, 29);
  const dt = new Date(2026, 4, 26);
  dt.setDate(dt.getDate() - daysAgo);
  dt.setHours(between(8, 21), between(0, 59));
  const sameRecipient = rng() < 0.45;
  const recFn = sameRecipient ? fn : pick(FIRST);
  const recLn = sameRecipient ? ln : pick(LAST);
  const slotDay = new Date(dt);
  slotDay.setDate(slotDay.getDate() + 1);
  const slotStart = between(9, 15);

  return {
    id: "#" + (64000 + i),
    custId: "C-" + (2200 + (Math.abs([...customer].reduce((a, c) => a + c.charCodeAt(0), 0)) % 60)),
    date: dt.toISOString().slice(0, 10),
    ts: dt.getTime(),
    time: dt.toLocaleString("en-GB", { hour: "2-digit", minute: "2-digit" }),
    customer,
    email: `${fn.toLowerCase()}.${ln.toLowerCase()}@${pick(["gmail.com", "yahoo.com", "hotmail.com", "outlook.com"])}`,
    phone: `0${between(6, 9)}${between(10000000, 99999999)}`.slice(0, 10),
    status,
    items: nItems,
    lines,
    subtotal,
    shipping,
    discount,
    total,
    margin: marginPct,
    prov,
    payment: pick(PAYMENTS),
    source: pick(SOURCES),
    fulfillment: fulfillmentFor(status),
    district: d[0],
    zip: d[1],
    billName: customer,
    billLines: [
      `${between(10, 99)}/${between(1, 99)} ${pick(["Sukhumvit", "Sathon", "Rama IV", "Phahonyothin", "Srinakarin"])} Rd`,
      `${d[0]}, Bangkok ${d[1]}`,
      "Thailand",
    ],
    shipName: `${recFn} ${recLn}`,
    shipLines: [
      `${between(10, 99)}/${between(1, 99)} ${pick(["Sukhumvit", "Thonglor", "Ekkamai", "Ari", "Silom"])} Rd`,
      `${d[0]}, Bangkok ${d[1]}`,
      "Thailand",
    ],
    slot: `${slotDay.toLocaleDateString("en-GB", { day: "numeric", month: "short" })} · ${String(
      slotStart,
    ).padStart(2, "0")}:00–${String(slotStart + 3).padStart(2, "0")}:00`,
    timeline: buildTimeline(status, dt),
  };
}

/* The 52 deterministic order records, newest first. */
export const ORDERS: OrderRecord[] = Array.from({ length: 52 }, (_, i) => genOrder(i + 1)).sort(
  (a, b) => b.ts - a.ts,
);

