/**
 * Fetcher for /api/v1/orders. Hits the same-origin Next proxy and
 * unwraps the CF success envelope before returning the inner shape.
 */

import type { ErrorEnvelope, SuccessEnvelope } from "../types/api";
import type { OrdersListResult, OrdersQueryParams } from "../types/orders";

const PROXY_BASE = "/api/proxy";

function buildSearch(p: OrdersQueryParams): string {
  const sp = new URLSearchParams();
  sp.set("account_id", p.account_id);
  if (p.workspace_id) sp.set("workspace_id", p.workspace_id);
  if (p.status) sp.set("status", p.status);
  if (p.date_from) sp.set("date_from", p.date_from);
  if (p.date_to) sp.set("date_to", p.date_to);
  if (p.limit != null) sp.set("limit", String(p.limit));
  if (p.offset != null) sp.set("offset", String(p.offset));
  return sp.toString();
}

export async function fetchOrders(params: OrdersQueryParams): Promise<OrdersListResult> {
  const res = await fetch(`${PROXY_BASE}/orders?${buildSearch(params)}`, {
    headers: { accept: "application/json" },
    cache: "no-store",
  });
  const body = (await res.json()) as SuccessEnvelope<OrdersListResult> | ErrorEnvelope;
  if (!res.ok || !body.ok) {
    const msg = !body.ok ? body.error?.message : `request_failed_${res.status}`;
    throw new Error(msg ?? "request_failed");
  }
  return body.data;
}
