/**
 * Adapter: API OrderRow → UI OrderRecord.
 *
 * The page's `OrderRecord` shape has many richer fields (line items,
 * timeline, billing/shipping addresses, margin, district, slot) that
 * today's listing endpoint doesn't return. Until the API exposes order
 * detail, those fields get empty / placeholder values — the table
 * itself renders fine; the row-expand detail panel just shows blanks
 * for the unavailable parts.
 */

import type {
  Fulfillment,
  LineItem,
  OrderRecord,
  OrderStatus,
  Payment,
  Provenance,
  Source,
} from "./data-orders-data";
import type { OrderRow } from "../types/orders";

const STATUS_MAP: Record<string, OrderStatus> = {
  completed: "completed",
  processing: "processing",
  cancelled: "cancelled",
  refunded: "refunded",
  // Common platform aliases.
  pending: "processing",
  "on-hold": "processing",
  failed: "cancelled",
};

const SOURCE_MAP: Record<string, Source> = {
  organic: "organic",
  google_ads: "google_ads",
  meta_ads: "meta_ads",
  facebook_ads: "meta_ads",
  instagram_ads: "meta_ads",
  direct: "direct",
  email: "email",
  klaviyo: "email",
  line_oa: "line_oa",
};

export function adaptOrders(rows: OrderRow[]): OrderRecord[] {
  return rows.map(buildRecord);
}

function buildRecord(r: OrderRow): OrderRecord {
  const dt = new Date(r.platform_created_at);
  const date = isoDate(dt);
  const status = STATUS_MAP[r.status.toLowerCase()] ?? "processing";
  const customer = r.customer_name ?? r.customer_email ?? "Customer";
  return {
    id: r.order_number ?? `#${r.id.slice(0, 8)}`,
    custId: r.id,
    date,
    ts: dt.getTime(),
    time: dt.toLocaleString("en-GB", { hour: "2-digit", minute: "2-digit" }),
    customer,
    email: r.customer_email ?? "",
    phone: "",
    status,
    items: r.item_count,
    lines: [] as LineItem[],
    subtotal: r.total,
    shipping: 0,
    discount: 0,
    total: r.total,
    margin: 0,
    prov: "partial" as Provenance,
    payment: mapPayment(r.payment_method),
    source: mapSource(r.source),
    fulfillment: fulfillmentFor(status),
    district: "—",
    zip: "—",
    billName: customer,
    billLines: [],
    shipName: customer,
    shipLines: [],
    slot: "",
    timeline: [["Order placed", dt.toLocaleString("en-GB", {
      day: "numeric",
      month: "short",
      hour: "2-digit",
      minute: "2-digit",
    })]],
  };
}

function isoDate(d: Date): string {
  return d.toISOString().slice(0, 10);
}

function mapPayment(raw: string | null): Payment {
  if (!raw) return "Credit Card";
  const low = raw.toLowerCase();
  if (low.includes("promptpay")) return "PromptPay";
  if (low.includes("bank")) return "Bank Transfer";
  return "Credit Card";
}

function mapSource(raw: string | null): Source {
  if (!raw) return "direct";
  return SOURCE_MAP[raw.toLowerCase()] ?? "direct";
}

function fulfillmentFor(status: OrderStatus): Fulfillment {
  if (status === "completed") return "delivered";
  if (status === "processing") return "processing";
  return "pending";
}
