"use client";

import { useQuery } from "@tanstack/react-query";
import { fetchOrders } from "../api/orders-api";
import type { OrdersQueryParams } from "../types/orders";
import { dataKeys } from "./data-keys";

export function useOrders(params: OrdersQueryParams | null) {
  return useQuery({
    queryKey: params ? dataKeys.orders(params) : dataKeys.all,
    queryFn: () => fetchOrders(params as OrdersQueryParams),
    enabled: Boolean(params?.account_id),
  });
}
